<?php
namespace App\Http\Requests\Admin\Content;use App\Domain\WorldCatalog\CatalogStatus;use App\Domain\WorldCatalog\ZoneType;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
class ZoneRequest extends FormRequest{public function authorize(){return true;}public function rules(){$zone=$this->route('zone');return['region_id'=>'required|integer|exists:regions,id','code'=>['required','string','max:64',Rule::unique('zones','code')->where(function($q){return$q->where('region_id',$this->input('region_id'));})->ignore($zone?$zone->id:null)],'name'=>'required|string|max:255','description'=>'nullable|string','zone_type'=>['required',Rule::in(ZoneType::values())],'recommended_level_min'=>'required|integer|min:1','recommended_level_max'=>'nullable|integer|gte:recommended_level_min','is_safe'=>'required|boolean','allows_hunting'=>'required|boolean','status'=>['required',Rule::in(CatalogStatus::values())],'sort_order'=>'required|integer|min:0'];}}
